//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "OP101",
    compID: "gr_CommodityList:cntrSizCd"
  }, {
    grpCd: "OP102",
    compID: "gr_CommodityList:cntrTypCd"
  }, {
    grpCd: "OP171",
    compID: "gr_CommodityList:fullEmptyClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions);
  scwin.f_defaultValue();
  scwin.f_createTree();
  titleLabel.hide("");
};

//-------------------------------------------------------------------------
// function name : f_defaultValue
// function desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
  $c.gus.cfDisableKey($p);
};

//-------------------------------------------------------------------------
// function name : f_createTree
// function desc : 화면 우측 Tree데이타 조회
//-------------------------------------------------------------------------
scwin.f_createTree = function () {
  $c.sbm.execute($p, sbm_commodity);
};

//-------------------------------------------------------------------------
// function name : f_Addrow
// function desc : 그리드 칼럼 추가
//-------------------------------------------------------------------------

scwin.f_Addrow = function (e) {
  let commCd = ds_commodity2.getCellData(ds_commodity2.getRowPosition(), "commCd");
  let pyPerTonCnt = ds_commodity2.getCellData(ds_commodity2.getRowPosition(), "pyPerTonCnt");
  let lvl = (Number(ds_commodity2.getCellData(ds_commodity2.getRowPosition(), "lvl")) || 0) + 1.0;
  let row = ds_commodityList.insertRow();
  ds_commodityList.setCellData(row, "upperCommCd", commCd);
  ds_commodityList.setCellData(row, "lvl", lvl);
  ds_commodityList.setCellData(row, "pyPerTonCnt", pyPerTonCnt);
  ds_commodityList.setCellData(row, "useYn", 1);
  gr_CommodityList.setFocusedCell(row, "commCd");
};

//-------------------------------------------------------------------------
// function name : f_Delrow
// function desc : 메인 그리드를 삭제했을 경우 sub그리드의 데이타까지 삭제
//-------------------------------------------------------------------------
scwin.f_Delrow = async function () {
  if (ds_commodityList.getRowStatus(ds_commodityList.getRowPosition()) == "C") {
    ds_commodityList.removeRow(ds_commodityList.getRowPosition());
  } else {
    if (ds_commodityList.getCellData(ds_commodityList.getRowPosition(), "lowerCnt") == 0) {
      var rowP = ds_commodityList.getRowPosition();
      ds_commodityList.deleteRow(ds_commodityList.getRowPosition());
      gr_CommodityList.setFocusedCell(rowP, 1);
    } else {
      await $c.win.alert($p, MSG_LO_WRN_002);
      return;
    }
  }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
  //변경한 데이터가 있는지 체크한다. 
  if (ds_commodityList.getModifiedIndex().length < 1) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["품명"]); //변경된 정보가 없습니다.
    return;
  }
  if (await scwin.f_ReqFieldChk()) {
    if (await $c.win.confirm($p, "저장하시겠습니까?")) {
      $c.sbm.execute($p, sbm_save);
    }
  }
};

//validate
scwin.f_ReqFieldChk = async function () {
  let lvl = ds_commodityList.getCellData(ds_commodityList.getRowPosition(), "lvl");
  if (lvl == "4") {
    if (ds_commodityList.getCellData(ds_commodityList.getRowPosition(), "kcgCd") == "") {
      $c.gus.cfAlertMsg($p, MSG_LO_WRN_001, ["레벨4(품명)일 경우 화종"]);
      return false;
    }
  }
  if (await $c.gus.cfValidate($p, [gr_CommodityList])) {
    return true;
  } else {
    return false;
  }
};

