//tree callback
scwin.sbm_commodity_submitdone = function () {
  // ds_commodity.insertRow(0);

  // ds_commodity.setCellData(0,"commNm","품명");
  // ds_commodity.setCellData(0,"commCd","1");
  // ds_commodity.setCellData(0,"lvl",0);
  // ds_commodity.setCellData(0,"treeLvl",1);

  ds_commodity2.removeAll();
  ds_commodity2.insertRow();
  ds_commodity2.setCellData(0, "commNm", "품명");
  ds_commodity2.setCellData(0, "lvl", 0);
  ds_commodity2.setCellData(0, "treeLvl", 1);
  ds_commodity2.setJSON(ds_commodity.getAllJSON(), true);
  tv_commodity.expandNode(1);

  //조회
  $c.sbm.execute($p, sbm_retrieve);
};

//조회 callback
scwin.sbm_retrieve_submitdone = function () {
  let nRow = ds_commodityList.getRowCount();
  total.setValue(nRow);
  tv_commodity.expandNode(1);
  if (nRow == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002, [""]);
  }
  gr_CommodityList.setFocusedCell(0, 0);
};

// tree Data 클릭시
// setCellDisableEdit -> setReadOnly, setCellColor -> setHeaderStyle 수정
scwin.tv_commodity_onclick = function () {
  let level = ds_commodity2.getCellData(ds_commodity2.getRowPosition(), "lvl");
  let commCd = ds_commodity2.getCellData(ds_commodity2.getRowPosition(), "commCd");
  if (level == "0") {
    gr_CommodityList.setHeaderValue("h_commCd", "하태코드");
    gr_CommodityList.setHeaderValue("h_commNm", "하태명");
  } else if (level == "1") {
    gr_CommodityList.setHeaderValue("h_commCd", "품목군코드");
    gr_CommodityList.setHeaderValue("h_commNm", "품목군명");
  } else if (level == "2") {
    gr_CommodityList.setHeaderValue("h_commCd", "품목코드");
    gr_CommodityList.setHeaderValue("h_commNm", "품목명");
  } else {
    gr_CommodityList.setHeaderValue("h_commCd", "품명코드");
    gr_CommodityList.setHeaderValue("h_commNm", "품명");
  }
  if (level == "3") {
    gr_CommodityList.setReadOnly("column", "kcgNm", false);
    gr_CommodityList.setReadOnly("column", "pyPerTonCnt", false);
    gr_CommodityList.setReadOnly("column", "cntrSizCd", false);
    gr_CommodityList.setReadOnly("column", "cntrTypCd", false);
    gr_CommodityList.setReadOnly("column", "fullEmptyClsCd", false);
    gr_CommodityList.setHeaderStyle("h_kcgNm", "color", "#FF0022");
    gr_CommodityList.setHeaderStyle("h_pyPerTonCnt", "color", "#007FFF");
    gr_CommodityList.setHeaderStyle("h_cntrSizCd", "color", "#007FFF");
    gr_CommodityList.setHeaderStyle("h_cntrTypCd", "color", "#007FFF");
    gr_CommodityList.setHeaderStyle("h_fullEmptyClsCd", "color", "#007FFF");
  } else if (level == "2") {
    gr_CommodityList.setReadOnly("column", "pyPerTonCnt", false);
    gr_CommodityList.setReadOnly("column", "cntrSizCd", false);
    gr_CommodityList.setReadOnly("column", "cntrTypCd", true);
    gr_CommodityList.setReadOnly("column", "fullEmptyClsCd", false);
    gr_CommodityList.setHeaderStyle("h_kcgNm", "color", "");
    gr_CommodityList.setHeaderStyle("h_pyPerTonCnt", "color", "#007FFF");
    gr_CommodityList.setHeaderStyle("h_cntrSizCd", "color", "#007FFF");
    gr_CommodityList.setHeaderStyle("h_cntrTypCd", "color", "");
    gr_CommodityList.setHeaderStyle("h_fullEmptyClsCd", "color", "#007FFF");
  } else {
    gr_CommodityList.setReadOnly("column", "kcgNm", true);
    gr_CommodityList.setReadOnly("column", "pyPerTonCnt", true);
    gr_CommodityList.setReadOnly("column", "cntrSizCd", true);
    gr_CommodityList.setReadOnly("column", "cntrTypCd", true);
    gr_CommodityList.setReadOnly("column", "fullEmptyClsCd", true);
    gr_CommodityList.setHeaderStyle("h_kcgNm", "color", "");
    gr_CommodityList.setHeaderStyle("h_pyPerTonCnt", "color", "");
    gr_CommodityList.setHeaderStyle("h_cntrSizCd", "color", "");
    gr_CommodityList.setHeaderStyle("h_cntrTypCd", "color", "");
    gr_CommodityList.setHeaderStyle("h_fullEmptyClsCd", "color", "");
  }
  titleLabel.show("");
  titleLabel.setValue(ds_commodity2.getCellData(ds_commodity2.getRowPosition(), "commNm"));

  //트리구조 데이타선택시 dataMap에 세팅
  dma_treeMap.set("upperCommCd", commCd);

  // commCd 정상가져옴
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_save_submitdone = async function () {
  await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다 
  //트리리로드 및 그리드 reset처리
  // scwin.f_createTree();

  $c.sbm.execute($p, sbm_commodity);

  //조회
  await $c.sbm.execute($p, sbm_retrieve);
};

//url call
scwin.btn_whajong_onclick = function (e) {
  $c.win.openMenu($p, "화종관리", "/ui/ds/lo/comninfomgnt/lo_100_03_02b.xml", "lo_100_03_02b.xml");
};

//tree 확장(expand)
scwin.btn_Expend_onclick = function (e) {
  if (btn_Expend.getValue() == "확장") {
    tv_commodity.spanAll(1, true, true);
    btn_Expend.setValue("접기");
  } else {
    tv_commodity.spanAll(false);
    tv_commodity.expandNode(1);
    btn_Expend.setValue("확장");
  }

  // tv_commodity.show(displayType)
};
scwin.gr_CommodityList_ontextimageclick = function (rowIndex, columnIndex) {
  scwin.gridPopUp(rowIndex);
};
scwin.gridPopUp = function (rowIndex) {
  rtnList = udc_kcgInfo.cfCommonPopUp(scwin.udc_kcgInfo_callBackFunc, ds_commodityList.getCellData(rowIndex, "kcgCd"), ds_commodityList.getCellData(rowIndex, "kcgNm"), "F", '5', null, '150,170', null, "1,2", '440', '500', null, null, null, 'F', null);
  ds_commodityList.setCellData(rowIndex, "kcgCd", "");
  ds_commodityList.setCellData(rowIndex, "kcgNm", "");
};

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.udc_kcgInfo_callBackFunc = function (rtnList) {
  let rowIdx = ds_commodityList.getRowPosition();
  if (rtnList != null) {
    if (rtnList[0] == "N/A") return;
    ds_commodityList.setCellData(rowIdx, "kcgCd", rtnList[0]);
    ds_commodityList.setCellData(rowIdx, "kcgNm", rtnList[1]);
  } else {
    ds_commodityList.setCellData(rowIdx, "kcgCd", "");
    ds_commodityList.setCellData(rowIdx, "kcgNm", "");
  }
};
scwin.gr_CommodityList_onviewchange = function (info) {
  if (info.colId == "kcgNm") {
    scwin.gridPopUp(info.rowIndex);
  }
};
